import json
import time
import hashlib
import secrets
from datetime import datetime, timedelta
from typing import Optional, Dict, Any

from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = secrets.token_hex(32)

# Initialize Web3
w3 = Web3()

# In-memory stores (replace with database in production)
nonce_store: Dict[str, Dict[str, Any]] = {}  # address -> {nonce, expires_at}
session_store: Dict[str, Dict[str, Any]] = {}  # session_token -> {address, expires_at, created_at}
user_store: Dict[str, Dict[str, Any]] = {}  # address -> {registered_at, last_login, login_count}

# Configuration
NONCE_EXPIRY_SECONDS = 300  # 5 minutes
SESSION_EXPIRY_SECONDS = 3600  # 1 hour
MESSAGE_TEMPLATE = "Sign this message to authenticate with Web3Auth.\n\nNonce: {nonce}\nTimestamp: {timestamp}\nDomain: web3auth.example.com"


def cleanup_expired_entries():
    """Remove expired nonces and sessions."""
    now = datetime.utcnow()
    
    expired_nonces = [
        addr for addr, data in nonce_store.items()
        if data['expires_at'] < now
    ]
    for addr in expired_nonces:
        del nonce_store[addr]
    
    expired_sessions = [
        token for token, data in session_store.items()
        if data['expires_at'] < now
    ]
    for token in expired_sessions:
        del session_store[token]


def generate_nonce() -> str:
    """Generate a cryptographically secure random nonce."""
    return secrets.token_hex(16)


def generate_session_token() -> str:
    """Generate a secure session token."""
    return secrets.token_urlsafe(48)


def is_valid_ethereum_address(address: str) -> bool:
    """Validate an Ethereum address."""
    try:
        return Web3.is_address(address) and Web3.is_checksum_address(Web3.to_checksum_address(address))
    except Exception:
        return False


def normalize_address(address: str) -> str:
    """Normalize an Ethereum address to checksum format."""
    return Web3.to_checksum_address(address)


def recover_signer(message: str, signature: str) -> Optional[str]:
    """Recover the signer address from a signed message."""
    try:
        encoded_message = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(
            encoded_message,
            signature=signature
        )
        return normalize_address(recovered_address)
    except Exception as e:
        app.logger.error(f"Signature recovery failed: {e}")
        return None


def require_auth(f):
    """Decorator to require authentication for endpoints."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({
                'success': False,
                'error': 'Missing or invalid Authorization header'
            }), 401
        
        token = auth_header.split('Bearer ')[1]
        
        session = session_store.get(token)
        if not session:
            return jsonify({
                'success': False,
                'error': 'Invalid session token'
            }), 401
        
        if session['expires_at'] < datetime.utcnow():
            del session_store[token]
            return jsonify({
                'success': False,
                'error': 'Session expired'
            }), 401
        
        request.user_address = session['address']
        request.session_token = token
        return f(*args, **kwargs)
    
    return decorated_function


@app.before_request
def before_request():
    """Run cleanup before each request."""
    cleanup_expired_entries()


