@require_auth
def refresh_session():
    """Refresh the current session token."""
    old_token = request.session_token
    address = request.user_address
    
    # Remove old session
    if old_token in session_store:
        del session_store[old_token]
    
    # Create new session
    now = datetime.utcnow()
    new_token = generate_session_token()
    session_store[new_token] = {
        'address': address,
        'created_at': now,
        'expires_at': now + timedelta(seconds=SESSION_EXPIRY_SECONDS)
    }
    
    return jsonify({
        'success': True,
        'data': {
            'session_token': new_token,
            'expires_in': SESSION_EXPIRY_SECONDS
        }
    }), 200


